using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool instances ---
var notepad = new Notepad();

// --- Create tools from static/instance methods ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// --- Agent setup ---
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:

        1. Use the web_search tool to find relevant information. Perform multiple
           searches with different queries to get a well-rounded view.
        2. Use the add_note tool to record key findings as you go.
        3. Use the get_notes tool to review what you have collected.
        4. After gathering enough information, synthesize your notes into a concise
           summary with key takeaways.

        Be thorough but concise. Cite sources when possible.
        """,
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
})
{
    // Agent handles tool dispatch internally; cap iterations to prevent runaway loops
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n");

// --- Tool Implementations ---

/// <summary>Simulates web search by fetching and summarizing real web content.</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information about a query. Returns a list of search result snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");

        try
        {
            // Use Wikipedia's API as a reliable, free search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json&utf8=1";

            var response = await s_http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(response);

            var results = new StringBuilder();
            var searchItems = doc.RootElement
                .GetProperty("query")
                .GetProperty("search");

            var index = 0;
            foreach (var item in searchItems.EnumerateArray())
            {
                index++;
                var title = item.GetProperty("title").GetString();
                // Strip HTML tags from the snippet
                var snippet = System.Text.RegularExpressions.Regex.Replace(
                    item.GetProperty("snippet").GetString() ?? "", "<.*?>", "");
                results.AppendLine($"{index}. **{title}**: {snippet}");
                results.AppendLine($"   Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title?.Replace(' ', '_') ?? "")}");
            }

            return results.Length > 0
                ? results.ToString()
                : "No results found for this query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }
}

/// <summary>A simple notepad tool that lets the agent record and review findings.</summary>
sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Add a research note. Use this to record key findings from search results.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");

        return sb.ToString();
    }
}

